// src/components/UserProfilePage.jsx
import { useState, useEffect } from "react";
import { updateProfile } from "firebase/auth";
import { doc, setDoc, getDoc, collection, query, where, getDocs, orderBy } from "firebase/firestore";
import { db } from "../firebase/config";
import { toast } from "react-hot-toast";
import AvatarPicker from "./AvatarPicker";

// ── Helpers ────────────────────────────────────────────────────────────────
const getUserDoc = (uid) => doc(db, "users", uid);

async function fetchUserProfile(uid) {
  const snap = await getDoc(getUserDoc(uid));
  return snap.exists() ? snap.data() : {};
}

async function saveUserProfile(uid, data) {
  await setDoc(getUserDoc(uid), data, { merge: true });
}

async function fetchUserPosts(uid) {
  try {
    const q = query(
      collection(db, "posts"),
      where("authorId", "==", uid),
      orderBy("createdAt", "desc")
    );
    const snap = await getDocs(q);
    return snap.docs.map((d) => ({ id: d.id, ...d.data() }));
  } catch {
    return [];
  }
}

function formatDate(ts) {
  if (!ts) return "";
  const d = ts.toDate ? ts.toDate() : new Date(ts);
  return d.toLocaleDateString("en-US", { month: "short", year: "numeric" });
}

// ── Sub-components ─────────────────────────────────────────────────────────
function StatPill({ label, value }) {
  return (
    <div style={{
      background: "var(--bg-2)", border: "1px solid var(--border)",
      borderRadius: 99, padding: "6px 18px", textAlign: "center",
    }}>
      <div style={{ fontFamily: "var(--font-display)", fontWeight: 800, fontSize: 20, color: "var(--ink)" }}>
        {value ?? 0}
      </div>
      <div style={{ fontSize: 11, color: "var(--muted)", letterSpacing: "0.06em", textTransform: "uppercase" }}>
        {label}
      </div>
    </div>
  );
}

function PostMiniCard({ post, onOpen }) {
  return (
    <article
      onClick={() => onOpen(post)}
      style={{
        background: "var(--card)", border: "1px solid var(--border)",
        borderRadius: "var(--radius)", overflow: "hidden",
        cursor: "pointer", transition: "transform 0.2s, box-shadow 0.2s",
        animation: "fadeUp 0.4s ease both",
      }}
      onMouseEnter={(e) => { e.currentTarget.style.transform = "translateY(-4px)"; e.currentTarget.style.boxShadow = "var(--shadow-lg)"; }}
      onMouseLeave={(e) => { e.currentTarget.style.transform = "translateY(0)"; e.currentTarget.style.boxShadow = "none"; }}
    >
      {post.imageUrl && (
        <div style={{ height: 140, overflow: "hidden" }}>
          <img src={post.imageUrl} alt={post.title}
            style={{ width: "100%", height: "100%", objectFit: "cover", transition: "transform 0.4s" }}
            onMouseEnter={(e) => (e.currentTarget.style.transform = "scale(1.05)")}
            onMouseLeave={(e) => (e.currentTarget.style.transform = "scale(1)")}
          />
        </div>
      )}
      <div style={{ padding: "14px 16px 16px" }}>
        {post.category && (
          <span style={{
            fontSize: 10, fontFamily: "var(--font-mono)", color: "var(--blue)",
            textTransform: "uppercase", letterSpacing: "0.1em",
            background: "var(--blue-glow)", padding: "2px 8px", borderRadius: 99,
          }}>{post.category}</span>
        )}
        <h3 style={{
          fontFamily: "var(--font-display)", fontSize: 15, fontWeight: 700,
          color: "var(--ink)", margin: "8px 0 4px", lineHeight: 1.3,
          display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical", overflow: "hidden",
        }}>{post.title}</h3>
        <div style={{ display: "flex", gap: 12, fontSize: 11, color: "var(--muted)", alignItems: "center" }}>
          <span>❤ {post.likes || 0}</span>
          <span>👁 {post.views || 0}</span>
          <span style={{ marginLeft: "auto" }}>{formatDate(post.createdAt)}</span>
        </div>
      </div>
    </article>
  );
}

function EditField({ label, value, onChange, multiline, placeholder }) {
  const shared = {
    width: "100%", padding: "10px 14px",
    border: "1px solid var(--border)", borderRadius: "var(--radius-sm)",
    fontFamily: "var(--font-body)", fontSize: 15,
    color: "var(--ink)", background: "var(--bg)", outline: "none",
    transition: "border-color 0.2s",
  };
  return (
    <label style={{ display: "block" }}>
      <div style={{ fontSize: 12, fontFamily: "var(--font-mono)", color: "var(--muted)", marginBottom: 6, letterSpacing: "0.06em", textTransform: "uppercase" }}>
        {label}
      </div>
      {multiline ? (
        <textarea value={value} onChange={(e) => onChange(e.target.value)}
          placeholder={placeholder} rows={3} style={{ ...shared, resize: "vertical" }}
          onFocus={(e) => (e.target.style.borderColor = "var(--blue)")}
          onBlur={(e) => (e.target.style.borderColor = "var(--border)")}
        />
      ) : (
        <input value={value} onChange={(e) => onChange(e.target.value)}
          placeholder={placeholder} style={shared}
          onFocus={(e) => (e.target.style.borderColor = "var(--blue)")}
          onBlur={(e) => (e.target.style.borderColor = "var(--border)")}
        />
      )}
    </label>
  );
}

// ── Main Component ─────────────────────────────────────────────────────────
export default function UserProfilePage({ currentUser, onClose, onOpenPost, allPosts = [], isDemo }) {
  const [tab, setTab] = useState("posts");
  const [profile, setProfile] = useState({ displayName: "", bio: "", website: "", photoURL: "" });
  const [userPosts, setUserPosts] = useState([]);
  const [loadingPosts, setLoadingPosts] = useState(true);
  const [saving, setSaving] = useState(false);
  const [followers, setFollowers] = useState([]);
  const [following, setFollowing] = useState([]);

  useEffect(() => {
    if (!currentUser) return;
    setProfile((p) => ({
      ...p,
      displayName: currentUser.displayName || "",
      photoURL: currentUser.photoURL || "",
    }));

    fetchUserProfile(currentUser.uid).then((data) => {
      setProfile((p) => ({ ...p, ...data }));
      setFollowers(data.followers || []);
      setFollowing(data.following || []);
    });

    fetchUserPosts(currentUser.uid).then((posts) => {
      if (posts.length === 0 && allPosts.length > 0) {
        const filtered = allPosts.filter(
          (p) => p.authorId === currentUser.uid || p.author === currentUser.displayName
        );
        setUserPosts(filtered);
      } else {
        setUserPosts(posts);
      }
      setLoadingPosts(false);
    });
  }, [currentUser]);

  const handleSave = async () => {
    if (!currentUser) return;
    setSaving(true);
    try {
      const { displayName, bio, website, photoURL } = profile;
      await updateProfile(currentUser, { displayName, photoURL });
      await saveUserProfile(currentUser.uid, { displayName, bio, website, photoURL });
      toast.success("Profile saved!");
      setTab("posts");
    } catch {
      toast.error("Save failed.");
    } finally {
      setSaving(false);
    }
  };

  if (!currentUser) {
    return (
      <div style={{ position: "fixed", inset: 0, zIndex: 200, background: "var(--bg)", display: "flex", alignItems: "center", justifyContent: "center", flexDirection: "column", gap: 16 }}>
        <p style={{ fontFamily: "var(--font-display)", fontSize: 20 }}>Sign in to view your profile.</p>
        <button onClick={onClose} style={{ background: "var(--blue)", color: "#fff", border: "none", borderRadius: 99, padding: "10px 24px", fontFamily: "var(--font-display)", fontWeight: 700, cursor: "pointer" }}>← Back</button>
      </div>
    );
  }

  const joinedDate = currentUser.metadata?.creationTime
    ? new Date(currentUser.metadata.creationTime).toLocaleDateString("en-US", { month: "long", year: "numeric" })
    : null;

  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 200, background: "var(--bg)", overflowY: "auto", animation: "fadeIn 0.3s ease" }}>

      {/* ── Top bar ── */}
      <div style={{
        position: "sticky", top: 0, zIndex: 10,
        background: "rgba(248,250,255,0.9)", backdropFilter: "blur(12px)",
        borderBottom: "1px solid var(--border)",
        display: "flex", alignItems: "center", padding: "0 24px", height: 56,
      }}>
        <button onClick={onClose} style={{ background: "none", border: "none", fontFamily: "var(--font-display)", fontSize: 14, color: "var(--blue)", cursor: "pointer", padding: "6px 0" }}>
          ← Back
        </button>
        <span style={{ position: "absolute", left: "50%", transform: "translateX(-50%)", fontFamily: "var(--font-display)", fontWeight: 800, fontSize: 16, color: "var(--ink)" }}>
          Profile
        </span>
      </div>

      {/* ── Cover ── */}
      <div style={{ position: "relative" }}>
        <div style={{ height: 180, background: "linear-gradient(135deg, #1d4ed8 0%, #3b82f6 50%, #93c5fd 100%)", position: "relative", overflow: "hidden" }}>
          <div style={{ position: "absolute", top: -40, right: -40, width: 200, height: 200, borderRadius: "50%", background: "rgba(255,255,255,0.07)" }} />
          <div style={{ position: "absolute", bottom: -60, left: 60, width: 160, height: 160, borderRadius: "50%", background: "rgba(255,255,255,0.05)" }} />
        </div>
        <div style={{ position: "absolute", bottom: -48, left: 32 }}>
          <div style={{
            width: 96, height: 96, borderRadius: "50%",
            border: "3px solid var(--border)", overflow: "hidden",
            background: "linear-gradient(135deg,#1d4ed8,#3b82f6)",
            display: "flex", alignItems: "center", justifyContent: "center",
            boxShadow: "0 4px 20px rgba(29,78,216,0.18)",
          }}>
            {profile.photoURL ? (
              <img src={profile.photoURL} alt="avatar" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
            ) : (
              <span style={{ fontFamily: "var(--font-display)", fontWeight: 800, fontSize: 32, color: "#fff" }}>
                {(profile.displayName || currentUser.email || "?")[0].toUpperCase()}
              </span>
            )}
          </div>
        </div>
      </div>

      {/* ── Content ── */}
      <div style={{ maxWidth: 760, margin: "0 auto", padding: "0 24px" }}>
        <div style={{ display: "flex", justifyContent: "flex-end", paddingTop: 12 }}>
          <button
            onClick={() => setTab(tab === "edit" ? "posts" : "edit")}
            style={{
              background: tab === "edit" ? "var(--blue)" : "var(--card)",
              color: tab === "edit" ? "#fff" : "var(--ink)",
              border: "1px solid var(--border)", borderRadius: 99,
              padding: "7px 20px", fontFamily: "var(--font-display)",
              fontWeight: 700, fontSize: 13, cursor: "pointer", transition: "all 0.2s",
            }}
          >
            {tab === "edit" ? "← Cancel" : "✎ Edit Profile"}
          </button>
        </div>

        <div style={{ marginTop: 16 }}>
          <h1 style={{ fontFamily: "var(--font-display)", fontWeight: 800, fontSize: 26, color: "var(--ink)", letterSpacing: "-0.03em" }}>
            {profile.displayName || currentUser.email?.split("@")[0] || "Anonymous"}
          </h1>
          {currentUser.email && (
            <div style={{ fontSize: 13, color: "var(--muted)", marginTop: 2, fontFamily: "var(--font-mono)" }}>
              {currentUser.email}
            </div>
          )}
          {profile.bio && (
            <p style={{ marginTop: 10, fontSize: 15, color: "var(--ink)", lineHeight: 1.6, maxWidth: 520 }}>
              {profile.bio}
            </p>
          )}
          <div style={{ display: "flex", gap: 16, marginTop: 8, flexWrap: "wrap", alignItems: "center" }}>
            {profile.website && (
              <a href={profile.website.startsWith("http") ? profile.website : `https://${profile.website}`}
                target="_blank" rel="noopener noreferrer"
                style={{ fontSize: 13, color: "var(--blue)", fontFamily: "var(--font-mono)" }}>
                🔗 {profile.website.replace(/^https?:\/\//, "")}
              </a>
            )}
            {joinedDate && <span style={{ fontSize: 12, color: "var(--muted)" }}>📅 Joined {joinedDate}</span>}
          </div>
        </div>

        <div style={{ display: "flex", gap: 10, marginTop: 20, flexWrap: "wrap" }}>
          <StatPill label="Posts" value={userPosts.length} />
          <StatPill label="Followers" value={followers.length} />
          <StatPill label="Following" value={following.length} />
        </div>

        <div style={{ height: 1, background: "var(--border)", margin: "28px 0" }} />

        {/* ── EDIT TAB ── */}
        {tab === "edit" && (
          <div style={{ animation: "fadeUp 0.3s ease", maxWidth: 560, paddingBottom: 60 }}>
            <h2 style={{ fontFamily: "var(--font-display)", fontSize: 20, marginBottom: 24 }}>Edit Profile</h2>

            {/* Avatar Picker card */}
            <div style={{
              background: "var(--bg-2)", border: "1px solid var(--border)",
              borderRadius: "var(--radius)", padding: 20, marginBottom: 24,
            }}>
              <div style={{ fontFamily: "var(--font-mono)", fontSize: 11, color: "var(--muted)", textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 16 }}>
                Choose Avatar
              </div>
              <AvatarPicker
                selected={profile.photoURL}
                onSelect={(url) => setProfile((p) => ({ ...p, photoURL: url }))}
                uid={currentUser.uid}
              />
            </div>

            <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
              <EditField label="Display Name" value={profile.displayName}
                onChange={(v) => setProfile((p) => ({ ...p, displayName: v }))} placeholder="Your name" />
              <EditField label="Bio" value={profile.bio || ""}
                onChange={(v) => setProfile((p) => ({ ...p, bio: v }))}
                placeholder="A short bio about yourself…" multiline />
              <EditField label="Website" value={profile.website || ""}
                onChange={(v) => setProfile((p) => ({ ...p, website: v }))} placeholder="yoursite.com" />
            </div>

            <button onClick={handleSave} disabled={saving}
              style={{
                marginTop: 24, background: "var(--blue)", color: "#fff",
                border: "none", borderRadius: 99, padding: "12px 32px",
                fontFamily: "var(--font-display)", fontWeight: 700, fontSize: 15,
                cursor: saving ? "wait" : "pointer", opacity: saving ? 0.7 : 1,
                transition: "opacity 0.2s, transform 0.2s",
                boxShadow: "0 4px 16px rgba(29,78,216,0.25)",
              }}
              onMouseEnter={(e) => !saving && (e.currentTarget.style.transform = "translateY(-2px)")}
              onMouseLeave={(e) => (e.currentTarget.style.transform = "translateY(0)")}
            >
              {saving ? "Saving…" : "Save Changes"}
            </button>
          </div>
        )}

        {/* ── POSTS TAB ── */}
        {tab === "posts" && (
          <div style={{ animation: "fadeUp 0.3s ease", paddingBottom: 60 }}>
            <h2 style={{ fontFamily: "var(--font-display)", fontSize: 20, marginBottom: 20 }}>Published Posts</h2>
            {loadingPosts ? (
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(220px,1fr))", gap: 16 }}>
                {[1, 2, 3].map((i) => (
                  <div key={i} style={{ height: 220, borderRadius: "var(--radius)", background: "linear-gradient(90deg,var(--bg-2) 25%,var(--border) 50%,var(--bg-2) 75%)", backgroundSize: "400px 100%", animation: "shimmer 1.4s infinite" }} />
                ))}
              </div>
            ) : userPosts.length === 0 ? (
              <div style={{ textAlign: "center", padding: "60px 20px", color: "var(--muted)" }}>
                <div style={{ fontSize: 40, marginBottom: 12 }}>✍️</div>
                <p style={{ fontSize: 16 }}>No posts yet. Start writing!</p>
              </div>
            ) : (
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))", gap: 16 }}>
                {userPosts.map((post, i) => (
                  <div key={post.id} style={{ animationDelay: `${i * 0.06}s` }}>
                    <PostMiniCard post={post} onOpen={onOpenPost} />
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}
